import React, { useState, useMemo } from 'react';
import ProductCard from '../components/ProductCard';
import { ProductCardSkeleton } from '../components/Skeleton';
import CategoryFilter from '../components/CategoryFilter';
import SearchBar from '../components/SearchBar';
import SortSelect, { SORT_OPTIONS } from '../components/SortSelect';
import { useCategories, useProductsByCategory } from '../hooks/useProducts';
import './ProductsPage.css';

function sortProducts(products, sortKey) {
  const arr = [...products];
  switch (sortKey) {
    case 'price-asc':   return arr.sort((a, b) => a.price - b.price);
    case 'price-desc':  return arr.sort((a, b) => b.price - a.price);
    case 'rating-desc': return arr.sort((a, b) => (b.rating?.rate ?? 0) - (a.rating?.rate ?? 0));
    case 'name-asc':    return arr.sort((a, b) => a.title.localeCompare(b.title));
    default:            return arr;
  }
}

export default function ProductsPage() {
  const [activeCategory, setActiveCategory] = useState('all');
  const [search, setSearch]                 = useState('');
  const [sort, setSort]                     = useState('default');

  const { categories } = useCategories();
  const { products, loading, error } = useProductsByCategory(activeCategory);

  const filtered = useMemo(() => {
    let list = products;
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(p =>
        p.title.toLowerCase().includes(q) ||
        p.category.toLowerCase().includes(q)
      );
    }
    return sortProducts(list, sort);
  }, [products, search, sort]);

  return (
    <main className="products-page">
      {/* Hero Banner */}
      <section className="products-hero">
        <div className="container">
          <p className="products-hero__eyebrow">New Collection</p>
          <h1 className="products-hero__title">Curated Finds<br />for Every Style</h1>
          <p className="products-hero__sub">
            {products.length} products · Free shipping over $50
          </p>
        </div>
        <div className="products-hero__bg" aria-hidden="true">
          <div className="products-hero__orb products-hero__orb--1" />
          <div className="products-hero__orb products-hero__orb--2" />
        </div>
      </section>

      {/* Toolbar */}
      <section className="products-toolbar">
        <div className="container products-toolbar__inner">
          <CategoryFilter
            categories={categories}
            active={activeCategory}
            onChange={setActiveCategory}
          />
          <div className="products-toolbar__right">
            <SearchBar value={search} onChange={setSearch} />
            <SortSelect value={sort} onChange={setSort} />
          </div>
        </div>
      </section>

      {/* Grid */}
      <section className="products-grid-section">
        <div className="container">
          {error && (
            <div className="products-error">
              <p>Failed to load products: {error}</p>
              <button onClick={() => window.location.reload()}>Retry</button>
            </div>
          )}

          {!error && (
            <>
              <div className="products-meta">
                {!loading && (
                  <span>{filtered.length} product{filtered.length !== 1 ? 's' : ''}</span>
                )}
              </div>

              {loading ? (
                <div className="products-grid">
                  {Array.from({ length: 8 }).map((_, i) => (
                    <ProductCardSkeleton key={i} />
                  ))}
                </div>
              ) : filtered.length === 0 ? (
                <div className="products-empty">
                  <p>No products match your search.</p>
                  <button onClick={() => { setSearch(''); setSort('default'); }}>
                    Clear filters
                  </button>
                </div>
              ) : (
                <div className="products-grid">
                  {filtered.map((product, i) => (
                    <div
                      key={product.id}
                      style={{ animationDelay: `${Math.min(i * 50, 400)}ms` }}
                    >
                      <ProductCard product={product} />
                    </div>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </section>
    </main>
  );
}
